(function (){'use strict';function initMobileNav(){var hamburgerBtn=document.querySelector('.hamburger-btn');var mobileNav=document.getElementById('mobile-menu');var body=document.body;if(!hamburgerBtn || !mobileNav)return ;function openMenu(){var scrollY=window.scrollY || window.pageYOffset;body.style.top='-'+scrollY+'px';mobileNav.classList.add('is-open');hamburgerBtn.classList.add('is-active');hamburgerBtn.setAttribute('aria-expanded','true');body.classList.add('nav-open');}function closeMenu(){var scrollY=parseInt(body.style.top || '0',10)* -1;body.classList.remove('nav-open');body.style.top='';mobileNav.classList.remove('is-open');hamburgerBtn.classList.remove('is-active');hamburgerBtn.setAttribute('aria-expanded','false');window.scrollTo(0,scrollY);}function toggleMenu(){if(mobileNav.classList.contains('is-open')){closeMenu();}else {openMenu();}}hamburgerBtn.addEventListener('click',toggleMenu);document.addEventListener('keydown',function (e){if(e.key==='Escape' && mobileNav.classList.contains('is-open')){closeMenu();hamburgerBtn.focus();}});document.addEventListener('click',function (e){if(mobileNav.classList.contains('is-open')&& !mobileNav.contains(e.target)&& !hamburgerBtn.contains(e.target)){closeMenu();}});var dropdownToggles=document.querySelectorAll('.mobile-dropdown-toggle');dropdownToggles.forEach(function (toggle){toggle.addEventListener('click',function (){var dropdown=toggle.closest('.mobile-dropdown');if(!dropdown)return ;var isOpen=dropdown.classList.contains('is-open');document.querySelectorAll('.mobile-dropdown.is-open').forEach(function (openDropdown){if(openDropdown !==dropdown){openDropdown.classList.remove('is-open');var otherToggle=openDropdown.querySelector('.mobile-dropdown-toggle');if(otherToggle){otherToggle.setAttribute('aria-expanded','false');}}});dropdown.classList.toggle('is-open',!isOpen);toggle.setAttribute('aria-expanded',!isOpen ? 'true' : 'false');});});}function initStickyCallButton(){var siteHeader=document.querySelector('.site-header');function onScroll(){var scrollY=window.scrollY || window.pageYOffset;if(siteHeader){if(scrollY > 60){siteHeader.classList.add('is-scrolled');}else {siteHeader.classList.remove('is-scrolled');}}}onScroll();window.addEventListener('scroll',onScroll,{passive: true});}if(document.readyState==='loading'){document.addEventListener('DOMContentLoaded',function (){initMobileNav();initStickyCallButton();});}else {initMobileNav();initStickyCallButton();}})();